import{_ as a,o as n,c as i,ag as p}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"第 11 章 搜索与发现工具","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/11-search-tools.md","filePath":"chapters/11-search-tools.md"}'),e={name:"chapters/11-search-tools.md"};function l(t,s,o,c,h,r){return n(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="第-11-章-搜索与发现工具" tabindex="-1">第 11 章 搜索与发现工具 <a class="header-anchor" href="#第-11-章-搜索与发现工具" aria-label="Permalink to &quot;第 11 章 搜索与发现工具&quot;">​</a></h1><blockquote><p>&quot;在一个足够大的代码库中，找到正确的文件比修改它更难。&quot; —— 匿名工程师</p></blockquote><p>代码搜索是开发者日常工作中最高频的操作之一。Claude Code 提供了三个层次分明的搜索工具：GlobTool 负责文件名模式匹配，GrepTool 负责文件内容搜索，LSPTool 则借助语言服务器提供语义级别的代码理解。本章将逐一剖析这三个工具的实现细节。</p><h2 id="_11-1-globtool-快速的文件发现" tabindex="-1">11.1 GlobTool：快速的文件发现 <a class="header-anchor" href="#_11-1-globtool-快速的文件发现" aria-label="Permalink to &quot;11.1 GlobTool：快速的文件发现&quot;">​</a></h2><p>GlobTool 位于 <code>src/tools/GlobTool/GlobTool.ts</code>，它的职责是根据模式匹配找到符合条件的文件路径。</p><h3 id="输入设计" tabindex="-1">输入设计 <a class="header-anchor" href="#输入设计" aria-label="Permalink to &quot;输入设计&quot;">​</a></h3><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/tools/GlobTool/GlobTool.ts, Lines 26-36</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> inputSchema</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> lazySchema</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  z.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">strictObject</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pattern: z.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">describe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;The glob pattern to match files against&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    path: z.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">optional</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">describe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;The directory to search in...&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>输入参数极其简洁——一个 glob 模式加一个可选的搜索目录。<code>pattern</code> 支持标准的 glob 语法，如 <code>**/*.ts</code> 匹配所有 TypeScript 文件，<code>src/**/test_*.py</code> 匹配 <code>src</code> 目录下所有以 <code>test_</code> 开头的 Python 文件。当 <code>path</code> 未指定时，默认使用当前工作目录。</p><h3 id="输出结构" tabindex="-1">输出结构 <a class="header-anchor" href="#输出结构" aria-label="Permalink to &quot;输出结构&quot;">​</a></h3><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/tools/GlobTool/GlobTool.ts, Lines 39-52</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 输出包含：</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   durationMs  -- 搜索耗时（毫秒）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   numFiles    -- 匹配的文件数量</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   filenames   -- 文件路径数组</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   truncated   -- 结果是否被截断</span></span></code></pre></div><p>输出中包含 <code>durationMs</code> 字段，这是一个常被忽视但很有价值的设计。它让 LLM 能够感知搜索性能——如果一次 glob 操作耗时过长，LLM 可以据此决定缩小搜索范围或调整策略。<code>truncated</code> 字段则告知调用方是否有更多结果未被返回，避免因结果截断导致的信息遗漏。</p><h3 id="并发安全与只读标记" tabindex="-1">并发安全与只读标记 <a class="header-anchor" href="#并发安全与只读标记" aria-label="Permalink to &quot;并发安全与只读标记&quot;">​</a></h3><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/tools/GlobTool/GlobTool.ts, Lines 57-80</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// buildTool 定义</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// isConcurrencySafe: true  -- 可安全并发执行</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// isReadOnly: true          -- 不修改任何状态</span></span></code></pre></div><p><code>isConcurrencySafe: true</code> 意味着多个 GlobTool 调用可以同时执行而不会互相干扰。这个属性在并行搜索场景中至关重要——当 LLM 需要同时在多个目录中查找不同类型的文件时，这些搜索可以并发进行，大幅缩短总耗时。</p><p><code>isReadOnly: true</code> 标记告知权限系统这个工具不会修改任何文件系统状态，因此可以跳过写入相关的权限检查。</p><p>实际的 glob 匹配逻辑委托给了 <code>src/utils/glob.ts</code> 工具模块。这个模块封装了底层的文件系统遍历和模式匹配算法，并对结果按修改时间排序——最近修改的文件排在前面，这符合开发者&quot;最近改动的文件最可能是我要找的&quot;的直觉。</p><h2 id="_11-2-greptool-基于-ripgrep-的内容搜索" tabindex="-1">11.2 GrepTool：基于 ripgrep 的内容搜索 <a class="header-anchor" href="#_11-2-greptool-基于-ripgrep-的内容搜索" aria-label="Permalink to &quot;11.2 GrepTool：基于 ripgrep 的内容搜索&quot;">​</a></h2><p>如果说 GlobTool 回答的是&quot;哪些文件存在&quot;，那么 GrepTool 回答的就是&quot;哪些文件包含特定内容&quot;。它的实现位于 <code>src/tools/GrepTool/GrepTool.ts</code>，底层依赖 ripgrep（<code>rg</code>）——一个以性能著称的文本搜索工具。</p><h3 id="丰富的输入参数" tabindex="-1">丰富的输入参数 <a class="header-anchor" href="#丰富的输入参数" aria-label="Permalink to &quot;丰富的输入参数&quot;">​</a></h3><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// src/tools/GrepTool/GrepTool.ts, Lines 33-79</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 输入参数：</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   pattern      -- 正则表达式搜索模式</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   path         -- 搜索路径（默认当前目录）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   glob         -- 文件名过滤（如 &quot;*.js&quot;）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   output_mode  -- &#39;content&#39; | &#39;files_with_matches&#39; | &#39;count&#39;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   &#39;-B&#39;         -- 匹配行之前的上下文行数</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   &#39;-A&#39;         -- 匹配行之后的上下文行数</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   &#39;-C&#39;         -- 前后上下文行数</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   &#39;-n&#39;         -- 显示行号</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   &#39;-i&#39;         -- 大小写不敏感</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   type         -- 文件类型过滤（如 &quot;js&quot;, &quot;py&quot;）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   head_limit   -- 限制返回结果数</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   offset       -- 跳过前 N 条结果</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//   multiline    -- 启用跨行匹配</span></span></code></pre></div><p>这套参数设计直接映射了 ripgrep 的核心选项，同时增加了 <code>head_limit</code> 和 <code>offset</code> 两个分页参数。参数名使用了 <code>-B</code>、<code>-A</code>、<code>-C</code>、<code>-n</code>、<code>-i</code> 这样的短横线前缀形式，与 <code>rg</code> 命令行参数保持一致。这种设计降低了 LLM 的学习成本——如果它知道如何使用 <code>rg</code>，就自然知道如何使用 GrepTool。</p><h3 id="三种输出模式" tabindex="-1">三种输出模式 <a class="header-anchor" href="#三种输出模式" aria-label="Permalink to &quot;三种输出模式&quot;">​</a></h3><p>GrepTool 提供三种输出模式，适应不同的使用场景：</p><ul><li><strong>content</strong>：返回匹配行的完整内容，支持上下文行。这是最详细的模式，适合需要阅读具体代码的场景</li><li><strong>files_with_matches</strong>：只返回包含匹配的文件路径。这是默认模式，适合快速定位文件</li><li><strong>count</strong>：返回每个文件中的匹配次数。适合评估某个模式在代码库中的分布情况</li></ul><h3 id="执行流程" tabindex="-1">执行流程 <a class="header-anchor" href="#执行流程" aria-label="Permalink to &quot;执行流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GrepTool.call({ pattern, path, glob, output_mode, ... })</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 解析搜索路径</span></span>
<span class="line"><span>  |     +-- path 已指定 -&gt; 使用指定路径</span></span>
<span class="line"><span>  |     +-- path 未指定 -&gt; 使用当前工作目录</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 构建 ripgrep 参数列表</span></span>
<span class="line"><span>  |     +-- --regexp &lt;pattern&gt;</span></span>
<span class="line"><span>  |     +-- --glob &lt;filter&gt;      (若指定)</span></span>
<span class="line"><span>  |     +-- --type &lt;filetype&gt;    (若指定)</span></span>
<span class="line"><span>  |     +-- -B/-A/-C &lt;context&gt;   (若指定)</span></span>
<span class="line"><span>  |     +-- -i                   (若大小写不敏感)</span></span>
<span class="line"><span>  |     +-- -U --multiline-dotall (若跨行匹配)</span></span>
<span class="line"><span>  |     +-- --line-number / --files-with-matches / --count</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 执行 rg 子进程 (src/utils/ripgrep.ts)</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 解析输出结果</span></span>
<span class="line"><span>  |     +-- content 模式 -&gt; 保留完整匹配内容</span></span>
<span class="line"><span>  |     +-- files_with_matches -&gt; 提取文件路径列表</span></span>
<span class="line"><span>  |     +-- count 模式 -&gt; 提取匹配计数</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 应用 offset 跳过</span></span>
<span class="line"><span>  +-- 应用 head_limit 截断</span></span>
<span class="line"><span>  +-- 返回格式化结果</span></span></code></pre></div><p><code>src/utils/ripgrep.ts</code> 作为 ripgrep 的封装层，负责将结构化参数转换为命令行调用，并解析 <code>rg</code> 的输出。选择 ripgrep 而非内置的正则搜索是一个务实的决策——ripgrep 在大型代码库上的搜索性能远超纯 JavaScript 实现，它默认忽略 <code>.gitignore</code> 中列出的文件，并且能够自动检测二进制文件并跳过。</p><h3 id="跨行匹配" tabindex="-1">跨行匹配 <a class="header-anchor" href="#跨行匹配" aria-label="Permalink to &quot;跨行匹配&quot;">​</a></h3><p><code>multiline</code> 参数开启后，GrepTool 会传递 <code>-U --multiline-dotall</code> 标志给 ripgrep，使得 <code>.</code> 可以匹配换行符，正则模式可以跨越多行。这在搜索跨行的代码结构时非常有用，例如查找特定的函数定义（函数签名可能跨越多行）或多行的配置块。</p><h2 id="_11-3-lsptool-语义级代码理解" tabindex="-1">11.3 LSPTool：语义级代码理解 <a class="header-anchor" href="#_11-3-lsptool-语义级代码理解" aria-label="Permalink to &quot;11.3 LSPTool：语义级代码理解&quot;">​</a></h2><p>GlobTool 和 GrepTool 都是基于文本的搜索工具——它们不理解代码的语义。LSPTool 则通过 Language Server Protocol 引入了语义层面的代码分析能力。</p><p>LSP 服务管理的核心位于 <code>src/services/lsp/manager.ts</code>，它负责语言服务器的生命周期管理——启动、初始化、通信和关闭。当 Claude Code 打开一个项目时，LSP manager 会根据项目中的文件类型决定启动哪些语言服务器（如 TypeScript 项目启动 <code>tsserver</code>，Python 项目启动 <code>pyright</code>）。</p><p><code>src/services/lsp/LSPDiagnosticRegistry.ts</code> 则维护了一个诊断信息的注册表。语言服务器会持续分析代码，报告错误、警告和提示信息。DiagnosticRegistry 收集这些信息并使其可被查询，让 LLM 能够了解代码中存在的问题。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LSP 交互流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>项目打开</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- LSP Manager 启动对应语言服务器</span></span>
<span class="line"><span>  |     +-- 发送 initialize 请求</span></span>
<span class="line"><span>  |     +-- 交换客户端/服务端能力</span></span>
<span class="line"><span>  |     +-- 发送 initialized 通知</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 持续分析</span></span>
<span class="line"><span>  |     +-- 文件变更 -&gt; textDocument/didChange</span></span>
<span class="line"><span>  |     +-- 诊断更新 -&gt; textDocument/publishDiagnostics</span></span>
<span class="line"><span>  |     +-- DiagnosticRegistry 收集并索引</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>  +-- 按需查询</span></span>
<span class="line"><span>        +-- 跳转到定义 -&gt; textDocument/definition</span></span>
<span class="line"><span>        +-- 查找引用 -&gt; textDocument/references</span></span>
<span class="line"><span>        +-- 获取诊断 -&gt; 从 Registry 查询</span></span></code></pre></div><p>LSP 的语义理解能力使得 Claude Code 可以执行文本搜索无法完成的操作：准确地找到一个符号的定义位置（而非所有出现该字符串的地方），找到一个函数的所有调用者，或者理解一个类型的继承关系。</p><h2 id="_11-4-三层搜索策略" tabindex="-1">11.4 三层搜索策略 <a class="header-anchor" href="#_11-4-三层搜索策略" aria-label="Permalink to &quot;11.4 三层搜索策略&quot;">​</a></h2><p>三个搜索工具形成了由粗到细的搜索策略：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>搜索粒度递进</span></span>
<span class="line"><span></span></span>
<span class="line"><span>GlobTool (文件级)       &quot;项目中有哪些 TypeScript 文件？&quot;</span></span>
<span class="line"><span>    |                    pattern: &quot;**/*.ts&quot;</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>GrepTool (内容级)       &quot;哪些文件中定义了 Router 类？&quot;</span></span>
<span class="line"><span>    |                    pattern: &quot;class Router&quot;</span></span>
<span class="line"><span>    v</span></span>
<span class="line"><span>LSPTool  (语义级)       &quot;Router.navigate 方法在哪里被调用？&quot;</span></span>
<span class="line"><span>                         textDocument/references</span></span></code></pre></div><p>LLM 在实际使用中会根据问题的性质灵活组合这三个工具。对于&quot;找到所有配置文件&quot;这类需求，GlobTool 足矣；对于&quot;找到处理认证逻辑的代码&quot;，GrepTool 更为合适；而对于&quot;这个函数的修改会影响哪些调用方&quot;，则需要 LSPTool 的语义分析能力。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>Claude Code 的搜索工具体系体现了分层设计的思想。GlobTool 在文件名层面提供快速的模式匹配，具备并发安全和只读的特性，适合大规模的文件发现任务。GrepTool 在文件内容层面提供基于 ripgrep 的高性能正则搜索，三种输出模式覆盖了从概览到详查的不同需求。LSPTool 在代码语义层面通过语言服务器协议提供类型感知的代码导航。三个工具从文本到语义逐层递进，共同构成了 LLM 理解和探索代码库的感知系统。这种分层架构的优势在于，简单的问题用轻量的工具快速解决，复杂的问题才调用重量级的语义分析，在响应速度和分析深度之间取得了良好的平衡。</p>`,41)])])}const g=a(e,[["render",l]]);export{k as __pageData,g as default};
